sql:
SELECT user_id, username, role
FROM users
WHERE role = 'athlete';

SELECT COUNT(DISTINCT athlete_id) AS total_olympic_athletes
FROM athlete_events
WHERE event_type = 'Olympic Games';

SELECT event_name, COUNT(athlete_id) as num_athletes
FROM athlete_events
GROUP BY event_name;

SELECT a.athlete_name, c.country_name 
FROM athletes a 
JOIN countries c ON a.residence_country = c.country_code;

external_knowledge:
'biggest global sports stage' refers to the 'World Championships' event;
combined weight means the sum of the weights of the athletes;
top five athletes are those who have the highest number of appearances in the World Championships.

sql:
SELECT athlete_name, passport_number 
FROM athletes 
WHERE residence_country = 'Spain';

SELECT sport_id, discipline_name 
FROM sports 
ORDER BY created_at DESC;

SELECT COUNT(*)
FROM athletes
WHERE residence_country = 'Spain';

external_knowledge:
-guys refers to male athletes;
-racing-related disciplines are those having 'racing' in their descriptions;
-active in more than one discipline means they participate in multiple sport disciplines involving racing.
